   130→/// Multi-layer cache manager with memory, disk, and network support
   131→///
   132→/// Implements a sophisticated caching strategy with three layers:
   133→/// 1. **Memory Cache**: Fastest access, limited size, LRU eviction
   134→/// 2. **Disk Cache**: Persistent storage, survives app restarts
   135→/// 3. **Network**: Fallback when data not available locally
   136→///
   137→/// ## Features
   138→///
   139→/// - **Multi-Layer Caching**: Automatic fallback through cache layers
   140→/// - **Smart Promotion**: Disk cache hits promoted to memory cache
   141→/// - **Write-Through**: Network writes populate all cache layers
   142→/// - **Flexible Strategies**: Support for different caching strategies
   143→/// - **Comprehensive Stats**: Track performance across all layers
   144→/// - **Type Safe**: Generic implementation for any value type
   145→///
   146→/// ## Example
   147→///
   148→/// ```dart
   149→/// final cacheManager = CacheManager<String, Activity>(
   150→///   config: CacheManagerConfig(
   151→///     memoryConfig: MemoryCacheConfig(maxSize: 100),
   152→///     diskConfig: DiskCacheConfig(maxCacheSize: 50 * 1024 * 1024),
   153→///   ),
   154→/// );
   155→/// await cacheManager.initialize();
   156→///
   157→/// // Get with network fallback
   158→/// final result = await cacheManager.get(
   159→///   'activity_123',
   160→///   networkFetcher: (key) async {
   161→///     return await apiService.getActivity(key);
   162→///   },
   163→/// );
   164→///
   165→/// // Put in all cache layers
   166→/// await cacheManager.put('activity_123', activity);
   167→///
   168→/// // Invalidate specific key
   169→/// await cacheManager.invalidate('activity_123');
   170→///
   171→/// // Clear all caches
   172→/// await cacheManager.clearAll();
   173→/// ```
   174→class CacheManager<K, V> {
   175→  /// Cache configuration
   176→  final CacheManagerConfig config;
   177→
   178→  /// Memory cache layer
   179→  late final MemoryCache<K, V> _memoryCache;
   180→
   181→  /// Disk cache layer
   182→  late final DiskCache _diskCache;
   183→
   184→  /// Combined cache statistics
   185→  late final CombinedCacheStats _combinedStats;
   186→
   187→  /// Whether cache manager has been initialized
   188→  bool _isInitialized = false;
   189→
   190→  /// Creates a new cache manager
   191→  CacheManager({
   192→    CacheManagerConfig? config,
   193→  }) : config = config ?? const CacheManagerConfig() {
   194→    _memoryCache = MemoryCache<K, V>(config: this.config.memoryConfig);
   195→    _diskCache = DiskCache(config: this.config.diskConfig);
   196→    _combinedStats = CombinedCacheStats(
   197→      memoryStats: _memoryCache.stats,
   198→      diskStats: _diskCache.stats,
   199→    );
   200→  }
   201→
   202→  /// Initialize the cache manager
   203→  ///
   204→  /// Must be called before using the cache manager. Initializes
   205→  /// the disk cache layer.
   206→  Future<void> initialize() async {
   207→    if (_isInitialized) return;
   208→
   209→    await _diskCache.initialize();
   210→    _isInitialized = true;
   211→  }
   212→
   213→  /// Ensure cache manager is initialized
   214→  Future<void> _ensureInitialized() async {
   215→    if (!_isInitialized) {
   216→      await initialize();
   217→    }
   218→  }
   219→
   220→  /// Get a value from cache with network fallback
   221→  ///
   222→  /// Checks memory cache first, then disk cache, and finally fetches
   223→  /// from network if not found locally. Promotes disk hits to memory
   224→  /// cache for faster subsequent access.
   225→  ///
   226→  /// The [networkFetcher] function is called only when the data is
   227→  /// not found in any cache layer.
   228→  ///
   229→  /// Returns [CacheResult] containing the value and its source.
   230→  Future<CacheResult<V>> get(
   231→    K key, {
   232→    required Future<V> Function(K key) networkFetcher,
   233→    CacheStrategy? strategy,
   234→    Duration? memoryTtl,
   235→    Duration? diskTtl,
   236→  }) async {
   237→    await _ensureInitialized();
   238→
