   240→
   241→    // Handle force refresh strategy
   242→    if (effectiveStrategy == CacheStrategy.forceRefresh) {
   243→      return await _fetchFromNetwork(key, networkFetcher,
   244→          memoryTtl: memoryTtl, diskTtl: diskTtl);
